ucs.kql:
let phish = EmailEvents | where Timestamp > ago(7d) | where AttachmentCount > 0 | where Subject has_any ("diplomatic","ASEAN","embassy","Ministry","visa","summit","meeting","agreement") or SenderFromDomain has_any ("gov.","mofa","mfa") | project PhishTime=Timestamp, NetworkMessageId, RecipientEmailAddress, SenderFromAddress, Subject;
let recipients = phish | distinct RecipientEmailAddress;
let office_spawn = DeviceProcessEvents | where Timestamp > ago(7d) | where InitiatingProcessFileName in~ ("winword.exe","excel.exe","powerpnt.exe","outlook.exe") | where FileName in~ ("rundll32.exe","regsvr32.exe","mshta.exe","wscript.exe","cscript.exe","powershell.exe","cmd.exe") | where AccountUpn in (recipients) or AccountName has_any (recipients) | project SpawnTime=Timestamp, DeviceId, DeviceName, AccountUpn, InitiatingProcessFileName, FileName, ProcessCommandLine, SpawnPID=ProcessId;
let lsass_touch = DeviceEvents | where Timestamp > ago(7d) | where ActionType in ("OpenProcessApiCall","ReadProcessMemoryApiCall") | extend p=parse_json(AdditionalFields) | where tostring(p.TargetImageFileName) endswith "lsass.exe" | where InitiatingProcessFileName !in~ ("MsMpEng.exe","svchost.exe","wininit.exe","csrss.exe","lsm.exe") | project LsassTime=Timestamp, DeviceId, InitiatingProcessFileName, InitiatingProcessCommandLine, InitiatingProcessParentFileName;
office_spawn | join kind=inner lsass_touch on DeviceId | where LsassTime between (SpawnTime .. SpawnTime + 2h) | join kind=inner phish on $left.AccountUpn == $right.RecipientEmailAddress | where SpawnTime between (PhishTime .. PhishTime + 24h) | project PhishTime, SpawnTime, LsassTime, DeviceName, AccountUpn, SenderFromAddress, Subject, InitiatingProcessFileName, FileName, ProcessCommandLine, InitiatingProcessFileName1, InitiatingProcessParentFileName

let suspicious_hosts = DeviceProcessEvents | where Timestamp > ago(7d) | where FileName in~ ("svchost.exe","explorer.exe","spoolsv.exe","services.exe","dllhost.exe","taskhostw.exe") | where FolderPath !startswith "C:\\Windows\\System32\\" and FolderPath !startswith "C:\\Windows\\SysWOW64\\" | project DeviceId, DeviceName, MasqProc=FileName, MasqPath=FolderPath, MasqPID=ProcessId, MasqTime=Timestamp;
let raw_or_unusual = DeviceNetworkEvents | where Timestamp > ago(7d) | where ActionType in ("ConnectionSuccess","ConnectionAttempt","InboundConnectionAccepted") | where Protocol in~ ("Icmp","Igmp","Gre","Raw") or (Protocol =~ "Tcp" and RemotePort !in (53,80,443,445,3389,8080,8443) and RemoteIPType == "Public") | where InitiatingProcessFileName in~ ("svchost.exe","explorer.exe","lsass.exe","spoolsv.exe","services.exe","winlogon.exe","dllhost.exe","taskhostw.exe") | summarize ConnCount=count(), Bytes=sum(toint(InitiatingProcessFileSize)), FirstSeen=min(Timestamp), LastSeen=max(Timestamp), Dests=make_set(RemoteIP, 25), Ports=make_set(RemotePort, 25) by DeviceId, DeviceName, InitiatingProcessFileName, InitiatingProcessFolderPath, Protocol | where ConnCount < 50;
raw_or_unusual | join kind=inner suspicious_hosts on DeviceId | where InitiatingProcessFolderPath == MasqPath or (InitiatingProcessFolderPath !startswith "C:\\Windows\\System32\\" and InitiatingProcessFolderPath !startswith "C:\\Windows\\SysWOW64\\") | extend RegionFilter = iif(DeviceName has_any ("asean","vn-","my-","th-","id-","ph-","sg-","in-","mofa","mfa","gov"),"in-scope","oos") | project FirstSeen, LastSeen, DeviceName, InitiatingProcessFileName, InitiatingProcessFolderPath, Protocol, Ports, Dests, ConnCount, RegionFilter | sort by FirstSeen asc
